def parse_time_to_minutes(val):
    """Переводит абсолютно любое значение в минуты."""
    if pd.isna(val):
        return 0
    if isinstance(val, pd.Timedelta):
        return int(val.total_seconds() // 60)
    if isinstance(val, (datetime, time)):
        return val.hour * 60 + val.minute
    if isinstance(val, (int, float)) and not isinstance(val, bool):
        return int(round(val * 60))
        
    val_str = str(val).strip()
    if val_str == "" or val_str.lower() in ["nan", "none"]:
        return 0
        
    if ":" in val_str:
        try:
            parts = val_str.split(":")
            return int(parts[0]) * 60 + int(parts[1])
        except:
            return 0
            
    try:
        val_str = val_str.replace(',', '.')
        hours = float(val_str)
        return int(round(hours * 60))
    except:
        return 0

def minutes_to_str(total_minutes):
    """Перевод ОБЩЕЙ СУММЫ минут обратно в красивую строку HH:MM"""
    hours = total_minutes // 60
    minutes = total_minutes % 60
    return f"{hours:02d}:{minutes:02d}"

def try_parse_date(cell_val):
    """Железобетонное распознавание даты (с поддержкой чисел Excel)."""
    if pd.isna(cell_val):
        return None
        
    if isinstance(cell_val, (pd.Timestamp, datetime, date)):
        if 2000 < cell_val.year < 2100:
            return pd.to_datetime(cell_val)
            
    if isinstance(cell_val, (int, float)):
        try:
            parsed_d = pd.to_datetime(cell_val, unit='D', origin='1899-12-30')
            if 2000 < parsed_d.year < 2100:
                return parsed_d
        except:
            pass
            
    cell_str = str(cell_val).strip()
    
    if ":" in cell_str or (cell_str.isdigit() and len(cell_str) > 2 and not (40000 < int(cell_str) < 60000)):
        return None
        
    if cell_str.isdigit() and 40000 < int(cell_str) < 60000:
        try:
            parsed_d = pd.to_datetime(int(cell_str), unit='D', origin='1899-12-30')
            if 2000 < parsed_d.year < 2100:
                return parsed_d
        except:
            pass
            
    if any(char in cell_str for char in ['.', '-', '/']):
        try:
            parsed_d = pd.to_datetime(cell_str, errors='coerce', dayfirst=True)
            if pd.notna(parsed_d) and 2000 < parsed_d.year < 2100:
                return parsed_d
        except:
            pass
            
    return None

def find_column_mapping(df):
    """Ищет строку заголовка по ключевым словам и возвращает индексы колонок."""
    for idx, row in df.iloc[:10].iterrows():
        row_vals = [str(cell).strip().lower() if pd.notna(cell) else "" for cell in row]
        
        has_name = any(kw in val for val in row_vals for kw in ["nimi", "name", "fio", "фио", "сотрудник"])
        has_date = any(kw in val for val in row_vals for kw in ["kuupäev", "date", "дата", "день"])
        
        if has_name and has_date:
            mapping = {
                "header_row_idx": idx,
                "name_col": None,
                "date_col": None,
                "in_col": None,
                "out_col": None,
                "total_col": None
            }
            
            for col_idx, val in enumerate(row_vals):
                if any(kw in val for kw in ["nimi", "name", "fio", "фио", "сотрудник"]):
                    if mapping["name_col"] is None:
                        mapping["name_col"] = col_idx
                elif any(kw in val for kw in ["kuupäev", "date", "дата", "день"]):
                    if mapping["date_col"] is None:
                        mapping["date_col"] = col_idx
                elif any(kw in val for kw in ["aeg tehases", "tehases", "tehase", "sisse", "вход", "внутри", "inside"]):
                    if not any(kw in val for kw in ["kokku", "total", "всего"]):
                        if mapping["in_col"] is None:
                            mapping["in_col"] = col_idx
                elif any(kw in val for kw in ["aeg välja", "väljas", "välja", "выход", "снаружи", "outside"]):
                    if mapping["out_col"] is None:
                        mapping["out_col"] = col_idx
                elif any(kw in val for kw in ["kokku", "total", "всего", "summa"]):
                    if mapping["total_col"] is None:
                        mapping["total_col"] = col_idx
                        
            if mapping["name_col"] is not None and mapping["date_col"] is not None:
                return mapping
    return None

def format_excel_sheet_in_memory(wb):
    """Применяет премиальное оформление к листу openpyxl."""
    ws = wb.active
    
    font_header = Font(name="Segoe UI", size=11, bold=True, color="FFFFFF")
    font_body = Font(name="Segoe UI", size=11, color="2F3542")
    font_red_text = Font(name="Segoe UI", size=11, bold=True, color="78281F")
    
    fill_header = PatternFill(start_color="2F3640", end_color="2F3640", fill_type="solid")
    fill_empty_row = PatternFill(start_color="F5F6FA", end_color="F5F6FA", fill_type="solid")
    fill_red_cell = PatternFill(start_color="FADBD8", end_color="FADBD8", fill_type="solid")
    
    thin_side = Side(border_style="thin", color="DCDDE1")
    thin_border = Border(left=thin_side, right=thin_side, top=thin_side, bottom=thin_side)
    
    align_center = Alignment(horizontal="center", vertical="center")
    align_left = Alignment(horizontal="left", vertical="center")
    
    ws.row_dimensions[1].height = 26
    for col_idx in range(1, ws.max_column + 1):
        cell = ws.cell(row=1, column=col_idx)
        cell.font = font_header
        cell.fill = fill_header
        cell.alignment = align_center if col_idx > 1 else align_left
        cell.border = thin_border
        
    for row_idx in range(2, ws.max_row + 1):
        ws.row_dimensions[row_idx].height = 20
        val_total = str(ws.cell(row=row_idx, column=3).value or '').strip()
        val_out = str(ws.cell(row=row_idx, column=5).value or '').strip()
        is_empty_day = val_total in ["00:00", "0", ""]
        
        for col_idx in range(1, ws.max_column + 1):
            cell = ws.cell(row=row_idx, column=col_idx)
            cell.font = font_body
            cell.border = thin_border
            cell.alignment = align_center if col_idx > 1 else align_left
            if is_empty_day:
                cell.fill = fill_empty_row
                
        if not is_empty_day and ":" in val_out:
            try:
                parts = val_out.split(":")
                hours = int(parts[0])
                mins = int(parts[1])
                if hours > 1 or (hours == 1 and mins > 0):
                    out_cell = ws.cell(row=row_idx, column=5)
                    out_cell.fill = fill_red_cell
                    out_cell.font = font_red_text
            except:
                pass
                
    ws.auto_filter.ref = ws.dimensions
    ws.freeze_panes = "A2"
    
    for col in ws.columns:
        max_len = max(len(str(cell.value or '')) for cell in col)
        col_letter = col[0].column_letter
        ws.column_dimensions[col_letter].width = max(max_len + 4, 13)
