# --- ФУНКЦИИ БАЗЫ ДАННЫХ ---
def init_db():
    with sqlite3.connect(DB_NAME) as conn:
        cursor = conn.cursor()
        cursor.execute("PRAGMA foreign_keys = ON;")
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS orders (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                order_number TEXT NOT NULL,
                description TEXT,
                deadline TEXT,
                status TEXT DEFAULT 'In production'
            )
        ''')
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS operations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                order_id INTEGER,
                op_name TEXT NOT NULL,
                start_date TEXT NOT NULL,
                end_date TEXT NOT NULL,
                status TEXT DEFAULT 'Pending',
                FOREIGN KEY (order_id) REFERENCES orders (id) ON DELETE CASCADE
            )
        ''')
        conn.commit()

def order_exists(number):
    with sqlite3.connect(DB_NAME) as conn:
        cursor = conn.cursor()
        cursor.execute("SELECT id FROM orders WHERE order_number = ?", (number,))
        return cursor.fetchone() is not None

def add_order(number, desc, deadline):
    with sqlite3.connect(DB_NAME) as conn:
        cursor = conn.cursor()
        cursor.execute("INSERT INTO orders (order_number, description, deadline) VALUES (?, ?, ?)", (number, desc, str(deadline)))
        conn.commit()

def add_operation(order_id, op_name, start, end):
    with sqlite3.connect(DB_NAME) as conn:
        cursor = conn.cursor()
        cursor.execute("INSERT INTO operations (order_id, op_name, start_date, end_date) VALUES (?, ?, ?, ?)", (order_id, op_name, str(start), str(end)))
        conn.commit()

def update_operation_status(op_id, new_status):
    with sqlite3.connect(DB_NAME) as conn:
        cursor = conn.cursor()
        cursor.execute("UPDATE operations SET status = ? WHERE id = ?", (new_status, op_id))
        conn.commit()

def delete_operation(op_id):
    with sqlite3.connect(DB_NAME) as conn:
        cursor = conn.cursor()
        cursor.execute("DELETE FROM operations WHERE id = ?", (op_id,))
        conn.commit()

def delete_order(order_id):
    with sqlite3.connect(DB_NAME) as conn:
        cursor = conn.cursor()
        cursor.execute("PRAGMA foreign_keys = ON;")
        cursor.execute("DELETE FROM orders WHERE id = ?", (order_id,))
        conn.commit()

def get_orders_list():
    with sqlite3.connect(DB_NAME) as conn:
        df = pd.read_sql_query("SELECT id, order_number FROM orders ORDER BY order_number ASC", conn)
        return df

def get_merged_data():
    with sqlite3.connect(DB_NAME) as conn:
        query = '''
            SELECT operations.id AS op_id, orders.id AS order_id, orders.order_number, 
                   orders.description, orders.deadline, operations.op_name, operations.start_date, 
                   operations.end_date, operations.status
            FROM operations
            JOIN orders ON operations.order_id = orders.id
        '''
        df = pd.read_sql_query(query, conn)
        return df

init_db()



# Helper to parse pasted text
def parse_pasted_text(text_data):
    if not text_data.strip():
        return None
    import io
    import re
    
    # 1. Сначала пробуем стандартное чтение таблицы (TSV/CSV)
    try:
        df = pd.read_csv(io.StringIO(text_data), sep='\t', header=None)
        if df.shape[1] >= 2:
            # Проверяем, есть ли хотя бы в одном столбце даты в формате DD.MM.YYYY
            has_date = False
            for col in df.columns:
                if df[col].astype(str).str.contains(r'\d{2}\.\d{2}\.\d{4}').any():
                    has_date = True
                    break
            if has_date:
                return df
    except:
        pass

    # 2. Если табличный парсинг не дал дат, делаем интеллектуальный построчный разбор
    lines = [line.strip() for line in text_data.split('\n') if line.strip()]
    records = []
    
    # Регулярное выражение для поиска дат DD.MM.YYYY
    date_regex = re.compile(r'\b(\d{2}\.\d{2}\.\d{4})\b')
    
    for idx, line in enumerate(lines):
        match = date_regex.search(line)
        if match:
            # Найдена строка с датой
            date_str = match.group(1)
            
            # Ищем имя сотрудника: первая строка выше даты, содержащая буквы
            name_str = None
            for prev_idx in range(idx - 1, -1, -1):
                prev_line = lines[prev_idx]
                if date_regex.search(prev_line):
                    break # дошли до другой даты
                if re.search(r'[A-Za-zА-Яа-яЁё]', prev_line):
                    name_str = prev_line
                    break
            
            # Если выше не нашли, ищем ниже (на всякий случай)
            if not name_str:
                for next_idx in range(idx + 1, len(lines)):
                    next_line = lines[next_idx]
                    if date_regex.search(next_line):
                        break
                    if re.search(r'[A-Za-zА-Яа-яЁё]', next_line):
                        name_str = next_line
                        break
            
            if not name_str:
                name_str = "Unknown"
                
            # Собираем все часы (числа < 24, исключая номер карты badge типа 8087)
            numbers = []
            
            def get_numbers_from_str(s):
                s_clean = s.replace(',', '.')
                return [float(x) for x in re.findall(r'\b\d+(?:\.\d+)?\b', s_clean)]
            
            # Числа на строке с датой (без самой даты)
            line_no_date = line.replace(date_str, '')
            for num in get_numbers_from_str(line_no_date):
                if num < 24: # Время работы не может быть больше 24 часов
                    numbers.append(num)
                    
            # Проверяем соседние строки на наличие цифр (без букв)
            for adj_idx in [idx - 1, idx + 1]:
                if 0 <= adj_idx < len(lines):
                    adj_line = lines[adj_idx]
                    if not re.search(r'[A-Za-zА-Яа-яЁё]', adj_line):
                        for num in get_numbers_from_str(adj_line):
                            if num < 24:
                                numbers.append(num)
                                
            # Переводим числовые часы в формат HH:MM
            def float_to_time_str(val):
                h = int(val)
                m = int(round((val - h) * 60))
                if m == 60:
                    h += 1
                    m = 0
                return f"{h:02d}:{m:02d}"
                
            in_val = "00:00"
            out_val = "00:00"
            total_val = "00:00"
            
            if len(numbers) >= 3:
                in_val = float_to_time_str(numbers[0])
                out_val = float_to_time_str(numbers[1])
                total_val = float_to_time_str(numbers[2])
            elif len(numbers) == 2:
                in_val = float_to_time_str(numbers[0])
                total_val = float_to_time_str(numbers[1])
            elif len(numbers) == 1:
                in_val = float_to_time_str(numbers[0])
                
            records.append({
                "Nimi": name_str,
                "Kuupäev": date_str,
                "Aeg tehases": in_val,
                "Aeg väljas": out_val,
                "Aeg kokku tehases": total_val
            })
            
    if records:
        return pd.DataFrame(records)
        
    return None

